from __future__ import annotations
import json
from pathlib import Path
from typing import Iterator, Optional
from lineage import PromptLineageRecord

class LineageStore:
    """Append-only NDJSON lineage store with simple day-partitioned files."""

    def __init__(self, base_dir: Path):
        self.base_dir = base_dir
        self.base_dir.mkdir(parents=True, exist_ok=True)

    def _file_for(self, timestamp_utc: float) -> Path:
        from datetime import datetime, timezone
        dt = datetime.fromtimestamp(timestamp_utc, tz=timezone.utc)
        return self.base_dir / f"lineage_{dt.strftime('%Y%m%d')}.ndjson"

    def append(self, record: PromptLineageRecord) -> None:
        path = self._file_for(record.timestamp_utc)
        with path.open("a") as f:
            f.write(record.to_ndjson_line() + "\n")

    def get(self, lineage_id: str) -> Optional[PromptLineageRecord]:
        for ndjson_file in sorted(self.base_dir.glob("lineage_*.ndjson"), reverse=True):
            for line in ndjson_file.read_text().splitlines():
                if not line:
                    continue
                data = json.loads(line)
                if data.get("lineage_id") == lineage_id:
                    return PromptLineageRecord(**data)
        return None

    def find_by_source_doc(self, source_doc_id: str) -> Iterator[PromptLineageRecord]:
        """Yield all records that used a specific document as a RAG source."""
        for ndjson_file in sorted(self.base_dir.glob("lineage_*.ndjson")):
            for line in ndjson_file.read_text().splitlines():
                if not line:
                    continue
                data = json.loads(line)
                sources = data.get("context_sources", [])
                if any(s.get("source_doc_id") == source_doc_id for s in sources):
                    yield PromptLineageRecord(**data)

    def find_by_session(self, session_id: str) -> list[PromptLineageRecord]:
        results = []
        for ndjson_file in sorted(self.base_dir.glob("lineage_*.ndjson")):
            for line in ndjson_file.read_text().splitlines():
                if not line:
                    continue
                data = json.loads(line)
                if data.get("session_id") == session_id:
                    results.append(PromptLineageRecord(**data))
        return results
